content:
{
  "mode": "io",
  "tests": [
    {
      "name": "basic_functionality",
      "input": "{\"action\":\"create\",\"content\":\"Learn ReactJS basics\"}",
      "output": "{\"status\":\"success\",\"message\":\"Content created successfully\"}",
      "notes": "Tests basic content creation functionality."
    },
    {
      "name": "retrieve_content",
      "input": "{\"action\":\"retrieve\",\"id\":1}",
      "output": "{\"status\":\"success\",\"data\":{\"id\":1,\"content\":\"Learn ReactJS basics\"}}",
      "notes": "Validates retrieval of existing content."
    },
    {
      "name": "update_content",
      "input": "{\"action\":\"update\",\"id\":1,\"content\":\"Learn ReactJS advanced topics\"}",
      "output": "{\"status\":\"success\",\"message\":\"Content updated successfully\"}",
      "notes": "Checks if content can be updated correctly."
    },
    {
      "name": "delete_content",
      "input": "{\"action\":\"delete\",\"id\":1}",
      "output": "{\"status\":\"success\",\"message\":\"Content deleted successfully\"}",
      "notes": "Ensures content can be deleted."
    },
    {
      "name": "invalid_action",
      "input": "{\"action\":\"invalid\",\"content\":\"Test\"}",
      "output": "{\"status\":\"error\",\"message\":\"Invalid action\"}",
      "notes": "Tests handling of invalid actions."
    },
    {
      "name": "retrieve_nonexistent_content",
      "input": "{\"action\":\"retrieve\",\"id\":999}",
      "output": "{\"status\":\"error\",\"message\":\"Content not found\"}",
      "notes": "Validates response for retrieving non-existent content."
    },
    {
      "name": "empty_content_creation",
      "input": "{\"action\":\"create\",\"content\":\"\"}",
      "output": "{\"status\":\"error\",\"message\":\"Content cannot be empty\"}",
      "notes": "Tests edge case of creating content with empty string."
    },
    {
      "name": "large_content_creation",
      "input": "{\"action\":\"create\",\"content\":\"" + "A".repeat(10000) + "\"}",
      "output": "{\"status\":\"success\",\"message\":\"Content created successfully\"}",
      "notes": "Tests handling of large content input."
    }
  ],
  "assumptions": "All actions are performed on a valid user session.",
  "notes": "Ensure to handle both valid and invalid inputs gracefully."
}
